// The state of a specific expansion unit during a port-forwarding auto-setup run
type ExpansionUnitState int

const (
	PF_AUTO_SETUP_UNIT_ALREADY_EXISTS ExpansionUnitState = iota // Expansion unit already exists, no further setup needed
	PF_AUTO_SETUP_UNIT_PENDING                                  // Currently trying to discover and setup this unit
	PF_AUTO_SETUP_UNIT_ADDED                                    // Expansion unit was successfully added
	PF_AUTO_SETUP_UNIT_ERROR                                    // Could not add this expansion unit
)

type ExpansionUnit struct {
	State  ExpansionUnitState // The state of this unit in this auto-setup
	ErrMsg string             // If state is PF_AUTO_SETUP_UNIT_ERROR this describes the error
}

// The state of a port-forwarding auto-setup run
type RunningState int

const (
	PF_AUTO_SETUP_NONE                  RunningState = iota // No port-forwarding auto-setup run available
	PF_AUTO_SETUP_RUNNING                                   // Port-forwarding auto-setup is currently running
	PF_AUTO_SETUP_CANCELED                                  // Port-forwarding auto-setup was canceled
	PF_AUTO_SETUP_FINISHED_WITH_ERROR                       // Port-forwarding auto-setup finished with an error
	PF_AUTO_SETUP_FINISHED_SUCCESSFULLY                     // Port-forwarding auto-setup finished successfully
)

// The status and expansion units of a port-forwarding auto-setup run
type Status struct {
	StartTime               time.Time               // UNIX timestamp (UTC) when the auto-setup was started
	RemainingExpansionUnits int32                   // Number of expansion units that still need to be discovered
	RunningState            RunningState            // The state of the last available auto-setup run
	ExpansionUnits          map[int32]ExpansionUnit // Results per expansion unit, mapped by their node index
}

// The status of the auto-setup changed
type StatusChangedEvent interface {
	event.Event
	NewStatus() Status // The new port-forwarding auto-setup status
	isStatusChangedEvent()
}

// Success code
const (
	SUCCESS                              int32 = 0
	ERR_PF_AUTO_SETUP_NOT_A_PRIMARY_UNIT int32 = 1
	ERR_PF_AUTO_SETUP_ALREADY_RUNNING    int32 = 2
	ERR_PF_AUTO_SETUP_INVALID_PARAM      int32 = 3
)

// Interface for running the port-forwarding auto-setup
type PortForwardingAutoSetup interface {
	idl.Object

	// Start the port-forwarding auto-setup. This will try to discover
	// units that are connected to a port-forwarding downstream interface
	// and configure them as port-forwarding expansion units, one-by-one.
	// The auto-setup will exit if any errors occurred or the number of
	// expansion units to discover was reached.
	//
	// The auto-setup can only be started on port-forwarding primary units.
	// It does not work with the USB downstream interface (will return
	// ERR_PF_AUTO_SETUP_INVALID_PARAM).
	//
	//	@param numberOfExpansionUnits    how many expansion units should this port-forwarding cascade have
	//	@param username                  the username that is used to log in to the expansion units
	//	@param password                  the password to log in to the expansion units
	//	@param newPassword               set a new password if an expansion unit needs to change the default password
	//	@param disableStrongPasswordReq  true to disable strong password requirements of the expansion unit
	//
	//	@return 0 if OK
	//	@return ERR_PF_AUTO_SETUP_NOT_A_PRIMARY_UNIT  this unit is not a port-forwarding primary unit
	//	@return ERR_PF_AUTO_SETUP_ALREADY_RUNNING     an earlier run of the port-forwarding auto-setup is still running
	//	@return ERR_PF_AUTO_SETUP_INVALID_PARAM       one of the parameters was invalid
	Start(ctx context.Context, numberOfExpansionUnits int32, username string, password string, newPassword string, disableStrongPasswordReq bool) (int32, error)

	// Get the status of a port-forwarding auto-setup.
	//
	//	@return the status
	GetStatus(ctx context.Context) (Status, error)

	// Cancel a running port-forwarding auto-setup
	Cancel(ctx context.Context) error
}
